148	  \label{lem:Scheme_HModule_prime_isPushoutModuleCatFreeSheaf}
149	  \lean{AlgebraicGeometry.Scheme.HModule'_isPushoutModuleCatFreeSheaf}
150	  \uses{def:Scheme_ModuleCat_free_isLeftAdjoint}
151	  Let $S$ be a Mayer--Vietoris square. The image of $S$ under the composite functor
152	  \[
153	    \text{Yoneda} \;\circ\; \text{whiskering with }(\ModuleCat.\free\,k) \;\circ\; \presheafToSheaf
154	  \]
155	  is a pushout square in the category of sheaves of $k$-modules.
156	\end{lemma}
157	
158	\begin{proof}
159	  \uses{def:Scheme_ModuleCat_free_isLeftAdjoint}
160	  \leanok
161	  The original square is a pushout. Post-composition with the sheafify-compose functor preserves pushouts because the free-$k$-module functor is a left adjoint. A canonical isomorphism translates the resulting square into the desired shape.
162	\end{proof}
