import re, pathlib
chapters = pathlib.Path('blueprint/src/chapters')
problems = []
for f in chapters.glob('*.tex'):
    content = f.read_text()
    for line_no, line in enumerate(content.splitlines(), 1):
        # Skip comments
        if line.lstrip().startswith('%'):
            continue
        # Find malformed annotations
        for m in re.finditer(r'\\\\(uses|proves|label|ref|cref|lean)\\{([^}]*)\\}', line):
            kind, arg = m.group(1), m.group(2)
            if arg.strip() == '':
                problems.append((str(f), line_no, kind, 'empty'))
            elif ',' in arg and any(p.strip()=='' for p in arg.split(',')):
                problems.append((str(f), line_no, kind, 'empty-item'))
print(len(problems), 'malformed annotations remain')
for p in problems[:20]:
    print(p)
